'use client';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/Card';
import { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/context/AuthContext';
import { User } from 'lucide-react';

interface UserProfile {
  name: string;
  email: string;
  role: string;
  profileInfo: string;
  createdAt: string;
}
export default function ProfilePage() {
  const { userRole, detailsProfile } = useAuth();
  if (!detailsProfile) {
    return <div className='text-center py-20 text-xl'>Loading profile...</div>;
  }

  return (
    <div className='min-h-screen bg-gradient-to-br from-purple-100 to-white p-6 flex items-center justify-center'>
      <motion.div
        initial={{ opacity: 0, y: 40 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.6 }}
        className='w-full max-w-lg'
      >
        <Card className='rounded-2xl shadow-lg border border-purple-300'>
          <CardContent className='flex flex-col items-center text-center p-8 space-y-4'>
            <User className='w-20 h-20 p-3 rounded-full border-2 border-purple-400 shadow-md' />
            <h2 className='text-2xl font-semibold'>{detailsProfile.name}</h2>
            <p className='text-gray-500'>{detailsProfile.email}</p>
            <div className='flex gap-6'>
              <p>Creat account</p>
              <p className='text-gray-600'>{detailsProfile.createdAt}</p>
            </div>
            {userRole === 'host' ? (
              <div className='flex gap-6'>
                <p>Stats Role :</p>
                <p className='text-gray-600'>{userRole}</p>
              </div>
            ) : (
              <></>
            )}
            {detailsProfile.profileInfo && (
              <div className='flex gap-6'>
                <p>profile Info</p>
                <p className='text-sm text-gray-700 italic'>
                  {detailsProfile.profileInfo}
                </p>
              </div>
            )}
            <Button
              variant='default'
              className='mt-4'
              asChild
            >
              <a href='/profile/edit'>Edit Profile</a>
            </Button>
          </CardContent>
        </Card>
      </motion.div>
    </div>
  );
}
